async function sendDemographicsEvent() {
  const payload = {
    participantId: PARTICIPANT_ID,
    response: {
      questionIndex: 0,
      questionType: "demographics",
      age: demographics.age,
      profession: demographics.profession,
      llmUsage: demographics.llmUsage,
      swedishLevel: demographics.swedishLevel,
    },
  };
  try {
    await fetch(RESULTS_ENDPOINT, { method: "POST", mode: "no-cors", body: JSON.stringify(payload) });
  } catch (err) {
    console.error("Failed to send demographics", err);
  }
}

function renderQuestion() {
  els.btnExit.hidden = false;
  els.btnExit.style.display = "";
  hideChoices(false);
  els.questionText.classList.remove("question-text--intro");
  const q = effectiveQuestions[currentIndex];
  const total = effectiveQuestions.length;
  const questionNumber = currentIndex + 1;

  els.questionLabel.textContent = `Fråga ${questionNumber}`;
  if (els.questionTitle) {
    const title = q.title ? q.title.trim() : "";
    els.questionTitle.hidden = title.length === 0;
    els.questionTitle.textContent = title;
  }
  els.questionText.textContent = q.text;
  els.questionTag.textContent = q.type || "Item";

  els.progressText.textContent = `Fråga ${questionNumber} av ${total}`;
  const progressRatio = total > 0 ? questionNumber / total : 0;
  els.progressBarInner.style.width = `${Math.round(progressRatio * 100)}%`;

  els.btnPrev.disabled = currentIndex === 0;
  els.btnNext.disabled = !answers[currentIndex] && currentIndex !== total - 1;
  els.btnNext.textContent = currentIndex === total - 1 ? "Klar" : "Nästa ▶";

  resetChoiceStyles();
  applyAnswerStyles();
  renderFeedback();
  updateScoreSummary();
}

function renderThread() {
  const thread = THREADS[currentThreadIndex];
  if (!thread) return;

  // All interaction is via per-comment inline buttons — hide global choice buttons
  hideChoices(true);
  if (els.questionTitle) els.questionTitle.hidden = true;

  // Ensure Avsluta is always visible during the survey (may have been hidden on intro screen)
  els.btnExit.hidden = false;
  els.btnExit.style.display = "";

  if (!redditAnswers[currentThreadIndex]) {
    redditAnswers[currentThreadIndex] = thread.comments.map(() => null);
  }
  const threadAnswers = redditAnswers[currentThreadIndex];

  if (els.subtitle) {
    els.subtitle.textContent =
      "Läs kommentarerna. Avgör för varje kommentar om den är skriven av en människa eller AI.";
  }

  els.questionLabel.textContent = `Tråd ${currentThreadIndex + 1} av ${THREADS.length}`;
  els.questionText.textContent = thread.questionText;

  if (els.commentsContainer) {
    els.commentsContainer.innerHTML = "";

    thread.comments.forEach((comment, idx) => {
      const ans = threadAnswers[idx];
      const row = document.createElement("div");
      let rowClass = "comment-row";

      if (ans !== null && ans) {
        rowClass += ans.choiceIsHuman ? " comment-row--picked-human" : " comment-row--picked-ai";
      }

      row.className = rowClass;

      const meta = document.createElement("div");
      meta.className = "comment-meta";

      if (redditShowingFeedback && ans) {
        const guess = ans.choiceIsHuman ? "Människa" : "AI";
        meta.textContent = `Kommentar ${idx + 1} · Din bedömning: ${guess}`;
      } else {
        meta.textContent = `Kommentar ${idx + 1}`;
      }
      row.appendChild(meta);

      const body = document.createElement("div");
      body.className = "comment-body";
      body.textContent = comment.text;
      row.appendChild(body);

      // Inline choice buttons — shown while answering, hidden after submit
      if (!redditShowingFeedback) {
        const btnRow = document.createElement("div");
        btnRow.className = "comment-choice-buttons";

        const btnH = document.createElement("button");
        btnH.type = "button";
        btnH.className = "comment-choice-btn comment-choice-human" + (ans && ans.choiceIsHuman === true ? " selected" : "");
        btnH.textContent = 'Människa';
        btnH.addEventListener("click", () => inlineRecordAnswer(idx, true));

        const btnA = document.createElement("button");
        btnA.type = "button";
        btnA.className = "comment-choice-btn comment-choice-ai" + (ans && ans.choiceIsHuman === false ? " selected" : "");
        btnA.textContent = 'AI';
        btnA.addEventListener("click", () => inlineRecordAnswer(idx, false));

        btnRow.appendChild(btnH);
        btnRow.appendChild(btnA);
        row.appendChild(btnRow);
      }

      els.commentsContainer.appendChild(row);
    });
  }

  const answeredCount = threadAnswers.filter(a => a !== null).length;
  const allAnswered = answeredCount === thread.comments.length;

  if (redditShowingFeedback) {
    els.progressText.textContent = `Resultat · Tråd ${currentThreadIndex + 1} av ${THREADS.length}`;
    els.progressBarInner.style.width = "100%";
    els.btnPrev.disabled = currentThreadIndex === 0;
    els.btnNext.disabled = false;
    els.btnNext.textContent = currentThreadIndex === THREADS.length - 1 ? "Nästa del ▶" : "Nästa tråd ▶";
    els.feedback.textContent = "";
    els.feedback.classList.remove("correct", "incorrect");
    updateScoreSummary();
  } else {
    els.progressText.textContent = `Tråd ${currentThreadIndex + 1} av ${THREADS.length} · ${answeredCount}/${thread.comments.length} bedömda`;
    const progressRatio = thread.comments.length > 0 ? answeredCount / thread.comments.length : 0;
    els.progressBarInner.style.width = `${Math.round(progressRatio * 100)}%`;
    els.btnPrev.disabled = currentThreadIndex === 0;
    els.btnNext.disabled = !allAnswered;
    els.btnNext.textContent = "Skicka svar ▶";
    els.feedback.textContent = "";
    els.feedback.classList.remove("correct", "incorrect");
  }
}

function inlineRecordAnswer(commentIdx, choiceIsHuman) {
  if (redditShowingFeedback) return;
  if (!redditAnswers[currentThreadIndex]) {
    redditAnswers[currentThreadIndex] = THREADS[currentThreadIndex].comments.map(() => null);
  }
  redditAnswers[currentThreadIndex][commentIdx] = { choiceIsHuman };
  renderThread();
}

function renderTransition() {
  els.btnExit.hidden = false;
  els.btnExit.style.display = "";

  if (els.subtitle) {
    els.subtitle.textContent =
      "Nu börjar nästa del: bedöm uppsatsabstrakt. Läs noggrant och avgör om texten är skriven av en människa eller AI.";
  }
  if (els.questionTitle) els.questionTitle.hidden = true;

  els.questionLabel.textContent = "Nästa del";
  els.questionTag.textContent = "Instruktion";
  els.questionText.textContent =
    "Du har nu bedömt kommentarer i en diskussionstråd. I nästa del får du läsa uppsatsabstrakt ett i taget och avgöra om de är skrivna av en människa eller av en AI.";

  if (els.commentsContainer) {
    els.commentsContainer.innerHTML = "";
  }

  els.progressText.textContent = "";
  els.progressBarInner.style.width = "0%";

  resetChoiceStyles();
  els.feedback.textContent = "";
  els.feedback.classList.remove("correct", "incorrect");

  hideChoices(true);
  els.btnPrev.disabled = false;
  els.btnNext.disabled = false;
  els.btnNext.textContent = "Starta abstrakt-delen ▶";

  updateScoreSummary();
}

function makeScoreBar(label, correct, answered) {
  const pct = answered > 0 ? Math.round((correct / answered) * 100) : 0;
  const wrap = document.createElement("div");
  wrap.className = "outro-score-block";

  const labelRow = document.createElement("div");
  labelRow.className = "outro-score-label";
  labelRow.innerHTML = `<span>${label}</span><span class="outro-score-fraction">${correct} / ${answered} (${pct}%)</span>`;
  wrap.appendChild(labelRow);

  const barOuter = document.createElement("div");
  barOuter.className = "outro-bar-outer";
  const barInner = document.createElement("div");
  barInner.className = "outro-bar-inner";
  barInner.style.width = "0%";
  barOuter.appendChild(barInner);
  wrap.appendChild(barOuter);

  // Animate bar after paint
  requestAnimationFrame(() => requestAnimationFrame(() => {
    barInner.style.width = `${pct}%`;
  }));

  return wrap;
}

function renderOutro() {
  hideChoices(true);
  if (els.questionTitle) els.questionTitle.hidden = true;
  els.btnExit.hidden = true;
  els.btnExit.style.display = "none";

  if (els.subtitle) {
    els.subtitle.textContent = "Tack för att du deltog!";
  }

  els.questionLabel.textContent = "Klart";
  els.questionTag.textContent = "Tack";

  const sections = computeSectionScores();
  const totals = computeTotalScoreSoFar();

  els.questionText.classList.add("question-text--intro");
  els.questionText.innerHTML =
    "<p>Tack för att du har genomfört undersökningen! :) </p>" +
    "<p>Nedan ser du dina resultat för varje del.</p>";

  if (els.commentsContainer) {
    els.commentsContainer.innerHTML = "";

    // Score bars
    const scoresWrap = document.createElement("div");
    scoresWrap.className = "outro-scores";
    scoresWrap.appendChild(makeScoreBar("Kommentarer", sections.comments.correct, sections.comments.answered));
    scoresWrap.appendChild(makeScoreBar("Abstrakt", sections.abstracts.correct, sections.abstracts.answered));
    scoresWrap.appendChild(makeScoreBar("Totalt", totals.correct, totals.answered));
    els.commentsContainer.appendChild(scoresWrap);

    // Reflection box
    const box = document.createElement("div");
    box.className = "outro-box";

    const reflLabel = document.createElement("p");
    reflLabel.className = "outro-refl-label";
    reflLabel.textContent = "Fanns det några tecken som fick dig att tro att en text var skriven av AI snarare än en människa? (frivilligt)";
    box.appendChild(reflLabel);

    const textarea = document.createElement("textarea");
    textarea.className = "outro-textarea";
    textarea.placeholder = "Skriv valfri motivering här...";
    textarea.rows = 4;
    box.appendChild(textarea);

    const actions = document.createElement("div");
    actions.className = "outro-actions";

    const submit = document.createElement("button");
    submit.type = "button";
    submit.className = "nav-button primary";
    submit.textContent = "Skicka reflektion";

    submit.addEventListener("click", async () => {
      const text = textarea.value.trim();
      if (!text) return;

      globalQuestionIndex += 1;
      const payload = {
        participantId: PARTICIPANT_ID,
        response: {
          questionIndex: globalQuestionIndex,
          questionType: "reasoning",
          questionText: text,
          isHumanLabel: "",
          userGuessIsHuman: "",
          isCorrect: "",
          totalCorrectSoFar: totals.correct,
          totalAnsweredSoFar: totals.answered,
          mode: "outro",
        },
      };

      try {
        await fetch(RESULTS_ENDPOINT, { method: "POST", mode: "no-cors", body: JSON.stringify(payload) });
        textarea.value = "";
        textarea.disabled = true;
        submit.textContent = "Tack för att du svarade!";
        submit.disabled = true;
      } catch (err) {
        console.error("Failed to send reasoning", err);
        submit.textContent = "Tack för att du svarade!";
        submit.disabled = true;
      }
    });

    actions.appendChild(submit);
    box.appendChild(actions);
    els.commentsContainer.appendChild(box);
  }

  els.progressText.textContent = "";
  els.progressBarInner.style.width = "0%";

  // Hide Nästa on the outro screen (renderCurrent already handles Tidigare and Avsluta)
  els.btnNext.hidden = true;
  els.btnNext.style.display = "none";

  updateScoreSummary();
}

function renderCurrent() {
  // Tidigare: always hidden on every screen
  els.btnPrev.hidden = true;
  els.btnPrev.style.display = "none";

  // Avsluta: visible on all screens except intro and outro
  const showExit = mode !== "intro" && mode !== "outro";
  els.btnExit.hidden = !showExit;
  els.btnExit.style.display = showExit ? "" : "none";

  // Nästa: always visible (individual render functions set disabled state)
  els.btnNext.hidden = false;
  els.btnNext.style.display = "";

  const shell = document.querySelector(".app-shell");
  if (shell) {
    shell.classList.toggle("theme-comments", mode === "reddit");
    shell.classList.toggle("theme-abstracts", mode === "abstracts");
  }
  if (mode === "intro") {
    renderIntro();
  } else if (mode === "demographics") {
    renderDemographics();
  } else if (mode === "reddit") {
    renderThread();
  } else if (mode === "transition") {
    renderTransition();
  } else if (mode === "outro") {
    renderOutro();
  } else {
    renderQuestion();
  }
}

function resetChoiceStyles() {
  [els.btnHuman, els.btnAi].forEach((btn) => {
    btn.classList.remove("selected", "selected-correct", "selected-incorrect", "disabled");
  });
}

function applyAnswerStyles() {
  const answer = answers[currentIndex];

  if (!answer) return;

  const selectedButton = answer.choiceIsHuman ? els.btnHuman : els.btnAi;

  selectedButton.classList.add("selected");
  [els.btnHuman, els.btnAi].forEach((btn) => btn.classList.add("disabled"));
}

function renderFeedback() {
  // No correctness feedback is shown during the survey.
  els.feedback.textContent = "";
  els.feedback.classList.remove("correct", "incorrect");
}

function updateScoreSummary() {
  const totals = computeTotalScoreSoFar();
  numAnswered = totals.answered;
  numCorrect = totals.correct;

  els.scoreCorrect.textContent = numCorrect.toString();
  els.scoreTotal.textContent = numAnswered.toString();
}

function recordAnswer(choiceIsHuman) {
  if (mode === "abstracts") {
    const existing = answers[currentIndex];
    if (existing) {
      existing.choiceIsHuman = choiceIsHuman;
    } else {
      answers[currentIndex] = { choiceIsHuman };
    }
    hasAnsweredCurrent = true;
    globalQuestionIndex += 1;
    sendAnswerEvent();
    renderCurrent();
    return;
  }
  if (mode === "reddit" && !redditShowingFeedback) {
    if (!redditAnswers[currentThreadIndex]) {
      redditAnswers[currentThreadIndex] = THREADS[currentThreadIndex].comments.map(() => null);
    }
    redditAnswers[currentThreadIndex][currentCommentIndex] = { choiceIsHuman };
    lastChoiceIsHuman = choiceIsHuman;
    globalQuestionIndex += 1;
    sendAnswerEvent();
    renderThread();
  }
}

function handleNext() {
  if (mode === "intro") {
    mode = "demographics";
    renderDemographics();
    return;
  }
  if (mode === "demographics") {
    sendDemographicsEvent();
    mode = "reddit";
    currentThreadIndex = 0;
    currentCommentIndex = 0;
    redditShowingFeedback = false;
    renderThread();
    return;
  }
  if (mode === "reddit") {
    if (redditShowingFeedback) {
      redditShowingFeedback = false;
      if (currentThreadIndex < THREADS.length - 1) {
        currentThreadIndex += 1;
        renderThread();
        return;
      }
      mode = "transition";
      renderTransition();
      return;
    }

    // Submit all answers for this thread at once, then show feedback
    const thread = THREADS[currentThreadIndex];
    const threadAnswers = redditAnswers[currentThreadIndex] || [];
    for (let c = 0; c < thread.comments.length; c++) {
      if (threadAnswers[c]) {
        globalQuestionIndex += 1;
        currentCommentIndex = c;
        lastChoiceIsHuman = threadAnswers[c].choiceIsHuman;
        sendAnswerEvent();
      }
    }
    redditShowingFeedback = true;
    renderThread();
    return;
  }

  if (mode === "transition") {
    // Start abstracts part
    mode = "abstracts";
    currentIndex = 0;
    hasAnsweredCurrent = !!answers[currentIndex];
    if (els.subtitle) {
      els.subtitle.textContent =
        "Läs abstraktet. Avgör om det är skrivet av en människa eller AI.";
    }
    renderQuestion();
    return;
  }

  if (mode === "outro") {
    // restart
    mode = "intro";
    currentIndex = 0;
    currentThreadIndex = 0;
    currentCommentIndex = 0;
    hasAnsweredCurrent = false;
    numCorrect = 0;
    numAnswered = 0;
    globalQuestionIndex = 0;
    redditAnswers = [];
    redditShowingFeedback = false;
    lastChoiceIsHuman = null;
    demographics = { age: null, profession: "", llmUsage: null, swedishLevel: null };
    renderCurrent();
    return;
  }

  const lastIndex = effectiveQuestions.length - 1;

  if (currentIndex === lastIndex) {
    const percent =
      answers.length === 0
        ? 0
        : Math.round(
            (numCorrect / Math.max(1, answers.filter(Boolean).length)) * 100
          );

    mode = "outro";
    renderOutro();
    return;
  }

  currentIndex = clampIndex(currentIndex + 1);
  hasAnsweredCurrent = !!answers[currentIndex];
  renderQuestion();
}

function handlePrev() {
  if (mode === "reddit") {
    if (redditShowingFeedback) {
      // Dismiss feedback, stay on current thread so user can review before moving on
      redditShowingFeedback = false;
      renderThread();
      return;
    }

    if (currentThreadIndex > 0) {
      currentThreadIndex -= 1;
      renderThread();
      return;
    }
  } else if (mode === "transition") {
    mode = "reddit";
    currentThreadIndex = THREADS.length - 1;
    redditShowingFeedback = true; // show the feedback of the last thread
    renderThread();
  } else if (mode === "abstracts") {
    if (currentIndex === 0) {
      // Go back to the transition screen
      mode = "transition";
      renderTransition();
      return;
    }
    currentIndex = clampIndex(currentIndex - 1);
    hasAnsweredCurrent = !!answers[currentIndex];
    renderQuestion();
  } else if (mode === "outro") {
    // Go back to the last abstracts question
    mode = "abstracts";
    currentIndex = clampIndex(effectiveQuestions.length - 1);
    hasAnsweredCurrent = !!answers[currentIndex];
    renderQuestion();
  }
}

function handleKeydown(event) {
  const target = event.target;
  const tagName = target && target.tagName ? target.tagName.toLowerCase() : "";
  const isTypingField =
    tagName === "textarea" ||
    tagName === "input" ||
    (target && target.isContentEditable);

  // Don't steal keystrokes while the user is typing
  if (isTypingField) return;

  if (event.key === "ArrowLeft") {
    event.preventDefault();
    if (!els.btnPrev.disabled) handlePrev();
  } else if (event.key === "ArrowRight" || event.key === "Enter") {
    event.preventDefault();
    if (!els.btnNext.disabled) handleNext();
  } else if (event.key.toLowerCase() === "h") {
    event.preventDefault();
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(true);
    }
  } else if (event.key.toLowerCase() === "a") {
    event.preventDefault();
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(false);
    }
  }
}

function init() {
  if (els.btnExit) {
    els.btnExit.addEventListener("click", () => {
      mode = "outro";
      renderOutro();
    });
  }
  if (!els.btnHuman || !els.btnAi) {
    console.error("Required DOM elements not found. Check index.html structure.");
    return;
  }

  els.btnHuman.addEventListener("click", () => {
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(true);
    } else if (mode === "reddit" && !redditShowingFeedback) {
      recordAnswer(true);
    }
  });

  els.btnAi.addEventListener("click", () => {
    if (mode === "abstracts" && !answers[currentIndex]) {
      recordAnswer(false);
    } else if (mode === "reddit" && !redditShowingFeedback) {
      recordAnswer(false);
    }
  });

  els.btnNext.addEventListener("click", handleNext);
  els.btnPrev.addEventListener("click", handlePrev);

  document.addEventListener("keydown", handleKeydown);

  renderCurrent();
}

window.addEventListener("DOMContentLoaded", init);
